'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';

export default function ProfilePage() {
  const router = useRouter();

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState({ type: '', text: '' });

  const [menuOpen, setMenuOpen] = useState(false);
  const [userMenu, setUserMenu] = useState<any>(null);

  const [formData, setFormData] = useState({
    id: '',
    name: '',
    cpf: '',
    email: '',
    phone: ''
  });

  const maskPhone = (value: string) => {
    return value
      .replace(/\D/g, '')
      .replace(/(\d{2})(\d)/, '($1) $2')
      .replace(/(\d{5})(\d)/, '$1-$2')
      .replace(/(-\d{4})\d+?$/, '$1');
  };

  useEffect(() => {
    const userStored = localStorage.getItem('user');
    const token = localStorage.getItem('token');

    if (!userStored || !token) {
      router.push('/login');
      return;
    }

    const user = JSON.parse(userStored);
    setUserMenu(user);

    async function fetchProfile() {
      try {
        const res = await fetch(`https://tranca-app.onrender.com/users/${user.id || user.userId}`);
        const data = await res.json();

        if (res.ok) {
          setFormData({
            id: data.id,
            name: data.name,
            cpf: data.cpf || '',
            email: data.email,
            phone: data.phone || ''
          });
        } else {
          setMsg({ type: 'error', text: 'Erro ao carregar dados.' });
        }
      } catch {
        setMsg({ type: 'error', text: 'Erro de conexão.' });
      } finally {
        setLoading(false);
      }
    }

    fetchProfile();
  }, [router]);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    router.push('/');
  };

  async function handleUpdate(e: React.FormEvent) {
    e.preventDefault();
    setSaving(true);
    setMsg({ type: '', text: '' });

    try {
      const res = await fetch(`https://tranca-app.onrender.com/users/${formData.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          email: formData.email,
          phone: formData.phone
        })
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error);

      setMsg({ type: 'success', text: 'Dados atualizados com sucesso!' });

      const oldUser = JSON.parse(localStorage.getItem('user') || '{}');
      localStorage.setItem('user', JSON.stringify({ ...oldUser, email: formData.email }));

    } catch (error: any) {
      setMsg({ type: 'error', text: error.message || 'Erro ao salvar.' });
    } finally {
      setSaving(false);
    }
  }

  if (loading) {
    return <div className="min-h-screen flex items-center justify-center">Carregando...</div>;
  }

  return (
    <div className="min-h-screen bg-beleza-50">

      {/* HEADER IGUAL HOME */}
      <header className="bg-beleza-250 backdrop-blur-sm shadow-sm sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 py-2 flex justify-between items-center">

          <div className="flex items-center gap-3">
            <img src="/logo.jpeg" className="h-20 w-20 rounded-md" />
          </div>

          <div className="relative">
            {userMenu && (
              <>
                <button
                  onClick={() => setMenuOpen(!menuOpen)}
                  className="flex items-center gap-2 text-sm font-medium text-beleza-700"
                >
                  Olá, {userMenu.name.split(' ')[0]}
                </button>

                {menuOpen && (
                  <div className="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-xl border border-beleza-100 py-2">
                    <Link href="/profile" className="block px-4 py-2 hover:bg-beleza-50">
                      👤 Meu Perfil
                    </Link>

                    <Link href="/my-appointments" className="block px-4 py-2 hover:bg-beleza-50">
                      📅 Meus Agendamentos
                    </Link>

                    <div className="h-px bg-beleza-100 my-1"></div>

                    <button onClick={handleLogout} className="w-full text-left px-4 py-2 text-red-500 hover:bg-red-50">
                      🚪 Sair
                    </button>
                  </div>
                )}
              </>
            )}
          </div>
        </div>
      </header>

      {/* CONTEÚDO */}
      <div className="max-w-4xl mx-auto py-10 px-4">

        <div className="bg-white rounded-2xl shadow border border-beleza-100 overflow-hidden">

          {/* HEADER PERFIL */}
          <div className="bg-beleza-900 p-6 text-white">
            <h1 className="text-xl font-bold">{formData.name}</h1>
            <p className="text-sm opacity-70">Gerencie seus dados</p>
          </div>

          <div className="p-6 space-y-6">

            {msg.text && (
              <div className={`p-3 rounded text-sm ${
                msg.type === 'success'
                  ? 'bg-green-100 text-green-700'
                  : 'bg-red-100 text-red-700'
              }`}>
                {msg.text}
              </div>
            )}

            <form onSubmit={handleUpdate} className="space-y-6">

              <div className="grid md:grid-cols-2 gap-4">
                <input disabled value={formData.name} className="bg-gray-100 p-3 rounded-lg" />
                <input disabled value={formData.cpf} className="bg-gray-100 p-3 rounded-lg" />
              </div>

              <div className="grid md:grid-cols-2 gap-4">
                <input
                  type="email"
                  value={formData.email}
                  onChange={(e) => setFormData({...formData, email: e.target.value})}
                  className="border p-3 rounded-lg"
                />

                <input
                  value={formData.phone}
                  onChange={(e) => setFormData({...formData, phone: maskPhone(e.target.value)})}
                  className="border p-3 rounded-lg"
                />
              </div>

              <div className="flex justify-end">
                <button
                  type="submit"
                  disabled={saving}
                  className="bg-beleza-500 hover:bg-beleza-900 text-white px-6 py-3 rounded-lg"
                >
                  {saving ? 'Salvando...' : 'Salvar'}
                </button>
              </div>

            </form>

          </div>
        </div>

      </div>
    </div>
  );
}